const SRE_H_LOGS={base:'font-family: "Segoe UI", Tahoma, sans-serif; font-size: 10px; font-weight: bold; padding: 2px 6px; border-radius: 3px;',astro:'background: #D4AF37; color: #000000; border: 1px solid #B8860B; border: 1px solid #00c853;',display:'background: #008080; color: #ffffff; border: 1px solid #004d4d; border: 1px solid #00c853;',eastermonday:'background: #77dd77; color: #000000; border: 1px solid #55aa55; border: 1px solid #00c853;'};document.addEventListener("DOMContentLoaded",function(){const systemInit=new Promise((resolve)=>{const bannerImg=document.getElementById("Banner");if(bannerImg){const banners=["https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner1.avif","https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner2.avif","https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner3.avif","https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner4.avif"];banners.map(src=>{const img=new Image();img.src=src;return img});let bnrCntr=0;setInterval(()=>{bannerImg.classList.add("banner-fade-out");setTimeout(()=>{bnrCntr=(bnrCntr+1)%banners.length;bannerImg.src=banners[bnrCntr];bannerImg.classList.remove("banner-fade-out")},500)},3500)}
const msgContainer=document.getElementById("holidayMsg");if(msgContainer){const holiday=getNextHoliday();msgContainer.innerHTML=`<p class="holiday-countdown ${holiday.style}">${holiday.msg}</p>`}
resolve("DOM and Assets initialized.")});systemInit.then(()=>{return new Promise(resolve=>window.addEventListener("load",resolve))}).then(()=>{triggerHumanSync()})});function triggerHumanSync(){const logStyle="color: #B5EAD7; font-family: 'Courier New', monospace; background: #1a1a1a; padding: 2px 5px; border-radius: 3px; border: 1px solid rgba(0, 230, 118, 0.3); text-shadow: 1px 1px 2px rgba(137, 43, 226, 0.568);";console.log("%c 🐂 SYNC BiotechProject: Mastering the beast. Passion and logic synchronized within the labyrinth.",logStyle)}
const HolidayCalcs={easter:(y)=>{const a=y%19,b=Math.floor(y/100),c=y%100;const d=Math.floor(b/4),e=b%4,f=Math.floor((b+8)/25);const g=Math.floor((b-f+1)/3),h=(19*a+b-d-g+15)%30;const i=Math.floor(c/4),k=c%4,l=(32+2*e+2*i-h-k)%7;const m=Math.floor((a+11*h+22*l)/451);const month=Math.floor((h+l-7*m+114)/31);const day=((h+l-7*m+114)%31)+1;return{month:month-1,day}},thanksgiving:(y)=>{const first=new Date(y,10,1).getDay();const day=22+(4-first+7)%7;return{month:10,day}},fixed:(m,d)=>()=>({month:m,day:d}),relative:(calcFn,offsetDays)=>(y)=>{const base=calcFn(y);const date=new Date(y,base.month,base.day+offsetDays);return{month:date.getMonth(),day:date.getDate()}}};const HOLIDAY_SCHEMA=[{name:"St. Patrick's Day",style:"st-patrick",wish:"Happy St. Paddy's!",icon:"☘️",calc:HolidayCalcs.fixed(2,17)},{name:"Easter",style:"easter",wish:"Happy Easter!",icon:"🐣",calc:HolidayCalcs.easter},{name:"Easter Monday",style:"eastermonday",wish:"Happy Easter Monday!",icon:"🧺",calc:HolidayCalcs.relative(HolidayCalcs.easter,1)},{name:"4th of July",style:"july4",wish:"Happy Independence Day!",icon:"🎆",calc:HolidayCalcs.fixed(6,4)},{name:"Halloween",style:"halloween",wish:"Spooky Halloween!",icon:"🎃",calc:HolidayCalcs.fixed(9,31)},{name:"Thanksgiving",style:"thanksgiving",wish:"Happy Thanksgiving!",icon:"🦃",calc:HolidayCalcs.thanksgiving},{name:"Christmas",style:"natale",wish:"Merry Christmas!",icon:"🎄",calc:HolidayCalcs.fixed(11,25)}];function getNextHoliday(){const now=new Date();const today=new Date(now.getFullYear(),now.getMonth(),now.getDate());const currentYear=today.getFullYear();console.log(`%c 🌕 ASTRO %c Syncing dynamic cycles for ${currentYear}`,SRE_H_LOGS.astro+SRE_H_LOGS.base,"color: #888; margin-left: 5px;");const upcoming=HOLIDAY_SCHEMA.map(h=>{let{month,day}=h.calc(currentYear);let date=new Date(currentYear,month,day);if(date<today){({month,day}=h.calc(currentYear+1));date=new Date(currentYear+1,month,day)}
const diff=Math.ceil((date-today)/86400000);return{...h,date,diff}}).sort((a,b)=>a.diff-b.diff);const next=upcoming[0];const isToday=next.diff===0;const logStyle=SRE_H_LOGS[next.style]||SRE_H_LOGS.display;console.log(`%c${next.icon} BiotechHoliday%c ${next.name}: ${isToday ? 'ACTIVE' : next.diff + 'd left'}`,logStyle+SRE_H_LOGS.base,"color: #bcbcbc; margin-left: 5px;");return{msg:isToday?`${next.icon} <span class="holiday-name ${next.style}">${next.wish}</span>`:`Only ${next.diff} days until ${next.icon} <span class="holiday-name ${next.style}">${next.name}</span>!`,style:next.style}}
function turnOnLight(){const img=document.getElementById('myImage');if(img){img.src='https://gitechnolo.github.io/biotechproject/Biotech-file/images/pic_bulbon.avif';img.classList.add('bulb-glow')}}
function turnOffLight(){const img=document.getElementById('myImage');if(img){img.src='https://gitechnolo.github.io/biotechproject/Biotech-file/images/pic_bulboff.avif';img.classList.remove('bulb-glow')}}(function(){const initFadeInSequence=()=>{const lines=document.querySelectorAll(".type-line");let currentLineIndex=0;const showNextLine=()=>{if(currentLineIndex>=lines.length)return;const line=lines[currentLineIndex];if(line.textContent.trim().length===0){setTimeout(showNextLine,50);return}
line.classList.add("is-visible");currentLineIndex++;setTimeout(showNextLine,500)};const observer=new IntersectionObserver((entries)=>{if(entries[0].isIntersecting){showNextLine();observer.disconnect()}},{threshold:0.2});const terminalWindow=document.querySelector(".terminal-window");if(terminalWindow)observer.observe(terminalWindow);};window.addEventListener("load",initFadeInSequence)})()